import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the mean and how do you calculate it?", a: "Mean is the arithmetic average. Add all values together, then divide by the number of values. For 2, 4, and 6, the mean is 12 divided by 3, which equals 4." },
  { q: "How do you find the median of a dataset?", a: "Sort the numbers from smallest to largest. If there is an odd number of values, the median is the middle value. If there is an even number, average the two middle values." },
  { q: "What is the mode and what if there are multiple modes?", a: "The mode is the value that appears most often. If more than one value ties for highest frequency, the dataset has multiple modes. If no value repeats, it has no mode." },
  { q: "How do you calculate range?", a: "Range is the maximum value minus the minimum value. It quickly shows the distance between the smallest and largest values in a dataset." },
  { q: "Which average should you use - mean median or mode?", a: "Use mean for balanced numeric data, median when outliers are present, and mode when you need the most common value or category." },
];

const parseNums = (input: string) => input.split(/[\s,;]+/).map(Number).filter((n) => Number.isFinite(n));
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";
const medianOf = (values: number[]) => {
  const mid = Math.floor(values.length / 2);
  return values.length % 2 ? values[mid] : (values[mid - 1] + values[mid]) / 2;
};

export default function MeanMedianModeCalculator() {
  const [input, setInput] = useState("3, 7, 7, 10, 14, 18");
  const stats = useMemo(() => {
    const nums = parseNums(input);
    if (!nums.length) return null;
    const sorted = [...nums].sort((a, b) => a - b);
    const sum = nums.reduce((total, value) => total + value, 0);
    const mean = sum / nums.length;
    const median = medianOf(sorted);
    const counts = new Map<number, number>();
    nums.forEach((value) => counts.set(value, (counts.get(value) || 0) + 1));
    const maxCount = Math.max(...counts.values());
    const modes = maxCount > 1 ? [...counts.entries()].filter(([, c]) => c === maxCount).map(([value]) => value) : [];
    const range = sorted[sorted.length - 1] - sorted[0];
    return { nums, sorted, sum, mean, median, mode: modes.length ? modes.join(", ") : "No mode", range, min: sorted[0], max: sorted[sorted.length - 1], count: nums.length };
  }, [input]);

  return (
    <>
      <SEOHead title="Free Mean Median Mode Calculator Online - Calculate All Averages Instantly | CalcHive" description="Free online mean, median, mode and range calculator. Enter any dataset and get mean, median, mode and range instantly with step by step solution. 100% free for students, no signup required." canonical="/mean-median-mode-calculator" keywords="free mean median mode calculator, mean median mode range calculator free online, calculate mean median mode free, average calculator free, statistics mean calculator free" category="Statistics Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Mean Median Mode and Range Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free mean median mode calculator to calculate mean median mode free plus range with clear step by step work.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <label htmlFor="mmm-dataset" className="text-sm font-semibold text-foreground block mb-2">Dataset</label>
          <textarea id="mmm-dataset" value={input} onChange={(event) => setInput(event.target.value)} rows={3} className="w-full px-4 py-3 rounded-xl border border-input bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all font-mono text-sm mb-6" />
          {stats ? <motion.div key={input} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 mb-4 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Mean</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-mean">{fmt(stats.mean)}</p><p className="text-white/70 text-sm mt-1">Count: {stats.count}</p></div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">{[["Median", fmt(stats.median)], ["Mode", stats.mode], ["Range", fmt(stats.range)], ["Sorted", stats.sorted.join(", ")]].map(([label, value]) => <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground font-medium mb-1">{label}</p><p className="text-sm font-extrabold text-foreground break-words">{value}</p></div>)}</div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">Mean = ({stats.nums.join(" + ")}) / {stats.count} = {fmt(stats.sum)} / {stats.count} = {fmt(stats.mean)}. Median is the middle of sorted data: {fmt(stats.median)}. Mode: {stats.mode}. Range = {fmt(stats.max)} - {fmt(stats.min)} = {fmt(stats.range)}.</p></div>
          </motion.div> : <p className="text-center text-muted-foreground py-4">Enter at least one number.</p>}
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Mean Median Mode and Range for Free</h2><p className="text-muted-foreground leading-relaxed">Enter comma-separated numbers and this mean median mode range calculator free online tool sorts the data and calculates each value instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">What is the Difference Between Mean Median and Mode</h2><p className="text-muted-foreground leading-relaxed">Mean is the arithmetic average, median is the middle value, and mode is the most common value. Range measures spread from minimum to maximum.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Average Calculator for Students and Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this average calculator free and statistics mean calculator free for classwork, quick data summaries, and checking manual calculations.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/mean-median-mode-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


